func GetPrint(wr io.Writer) error {
	tmpl, err := template.New("").Parse(versionTemplate)
	if err != nil {
		return err
	}

	v := struct {
		Version		string
		Codename	string
		GoVersion	string
		BuildTime	string
		Os		string
		Arch		string
	}{
		Version:	version.Version,
		Codename:	version.Codename,
		GoVersion:	runtime.Version(),
		BuildTime:	version.BuildDate,
		Os:		runtime.GOOS,
		Arch:		runtime.GOARCH,
	}

	return tmpl.Execute(wr, v)
}
